import React from 'react';

const Hero = () => {
    const colors = { textMain: '#fef3c7', accent: '#ea580c', textMuted: '#a3a3a3' };

    return (
        <section style={{ padding: '100px 40px', textAlign: 'center', background: '#080402', color: colors.textMain, position: 'relative', overflow: 'hidden' }}>
            <div style={{
                position: 'absolute',
                top: '20%',
                left: '10%',
                width: '300px',
                height: '300px',
                background: 'radial-gradient(circle, rgba(234,88,12,0.08) 0%, transparent 70%)',
                borderRadius: '50%',
                animation: 'float 6s ease-in-out infinite',
            }} />
            <div style={{
                position: 'absolute',
                bottom: '10%',
                right: '5%',
                width: '250px',
                height: '250px',
                background: 'radial-gradient(circle, rgba(245,158,11,0.06) 0%, transparent 70%)',
                borderRadius: '50%',
                animation: 'float 8s ease-in-out infinite reverse',
            }} />
            <div style={{ maxWidth: '900px', margin: '0 auto', position: 'relative', zIndex: 1 }}>
                <span style={{ color: colors.accent, fontWeight: '800', letterSpacing: '3px', fontSize: '13px', textTransform: 'uppercase', background: 'rgba(234,88,12,0.1)', padding: '6px 16px', borderRadius: '30px', display: 'inline-block', marginBottom: '24px' }}>
                    ✨ #1 Portal Karir di Solo Raya
                </span>
                <h1 style={{ fontSize: '4rem', margin: '20px 0', lineHeight: '1.1', fontWeight: '900', letterSpacing: '-0.02em' }}>
                    Wujudkan <br/> <span style={{ color: colors.accent }}>Potensi Terbesarmu</span>
                </h1>
                <p style={{ color: colors.textMuted, fontSize: '18px', marginBottom: '40px', lineHeight: '1.6', maxWidth: '600px', margin: '0 auto 40px auto' }}>
                    Temukan ribuan lowongan dari perusahaan terpercaya, 
                    mulai karirmu hari ini bersama <strong style={{ color: colors.accent }}>PasukanYerusSolo</strong>
                </p>
                <button 
                    style={{ padding: '16px 48px', background: 'linear-gradient(135deg, #ea580c 0%, #f59e0b 100%)', border: 'none', borderRadius: '12px', color: '#fff', fontWeight: '800', cursor: 'pointer', transition: 'all 0.3s ease', boxShadow: '0 4px 20px rgba(234, 88, 12, 0.3)', fontSize: '16px' }}
                    onMouseEnter={(e) => {
                        e.currentTarget.style.transform = 'translateY(-3px)';
                        e.currentTarget.style.boxShadow = '0 8px 30px rgba(234, 88, 12, 0.5)';
                    }}
                    onMouseLeave={(e) => {
                        e.currentTarget.style.transform = 'translateY(0)';
                        e.currentTarget.style.boxShadow = '0 4px 20px rgba(234, 88, 12, 0.3)';
                    }}
                >
                    Mulai Eksplorasi →
                </button>
            </div>
            <style>{`
                @keyframes float {
                    0%, 100% { transform: translateY(0px) translateX(0px); }
                    50% { transform: translateY(-20px) translateX(10px); }
                }
            `}</style>
        </section>
    );
};
export default Hero;
